<template><el-dialog :model-value="visible" title="电脑信息" width="720px" destroy-on-close @update:model-value="emit('update:visible', $event)"><el-descriptions :column="2" border><el-descriptions-item label="品牌">{{ row?.brand || '-' }}</el-descriptions-item><el-descriptions-item label="型号">{{ row?.model || '-' }}</el-descriptions-item><el-descriptions-item label="序列号">{{ row?.serial_no || '-' }}</el-descriptions-item><el-descriptions-item label="状态"><el-tag v-if="row?.status==='IN_STOCK'" type="success">在库</el-tag><el-tag v-else-if="row?.status==='ASSIGNED'" type="warning">已领用</el-tag><el-tag v-else-if="row?.status==='RECYCLED'" type="info">已回收</el-tag><el-tag v-else type="danger">已报废</el-tag></el-descriptions-item><el-descriptions-item label="出厂日期">{{ row?.manufacture_date || '-' }}</el-descriptions-item><el-descriptions-item label="保修到期">{{ row?.warranty_end || '-' }}</el-descriptions-item><el-descriptions-item label="硬盘容量">{{ row?.disk_capacity || '-' }}</el-descriptions-item><el-descriptions-item label="内存大小">{{ row?.memory_size || '-' }}</el-descriptions-item><el-descriptions-item label="配置日期">{{ row?.last_config_date || '-' }}</el-descriptions-item><el-descriptions-item label="回收日期">{{ row?.last_recycle_date || '-' }}</el-descriptions-item><el-descriptions-item label="当前领用人" :span="2"><div v-if="row?.status==='ASSIGNED'"><div class="strong">{{ row?.last_employee_name || '-' }}</div><div class="subtle">{{ row?.last_employee_no || '-' }} · {{ row?.last_department || '-' }}</div></div><span v-else>-</span></el-descriptions-item><el-descriptions-item label="备注" :span="2"><div class="remark">{{ row?.remark || '-' }}</div></el-descriptions-item></el-descriptions><template #footer><el-button @click="emit('update:visible', false)">关闭</el-button></template></el-dialog></template>
<script setup lang="ts">defineProps<{ visible:boolean; row:Record<string,any>|null }>(); const emit = defineEmits<{ 'update:visible':[boolean] }>();</script>
<style scoped>.strong{font-weight:600}.subtle{color:#999;font-size:12px}.remark{white-space:pre-wrap}</style>
